const body = $input.first().json.body || $input.first().json;
const event_id = body.event_id || '';
const project_id = body.project_id || '';
const event_type = body.event_type || 'MATERIALS_CALCULATED';
const payload = body.payload || {};

return [{ json: { event_id, project_id, event_type, payload } }];

const data = $input.first().json;
const projectId = $('Parse Event Data').first().json.project_id;
const materials = data.materials || [];
const schedule = data.schedule || [];
const pn = data.project_number || '';
const name = data.project_name || '';

if (!materials || materials.length === 0) {
  return [{ json: { text: '\u26a0\ufe0f Keine Materialien berechnet f\u00fcr ' + pn, projectId, hasMaterials: false } }];
}

// Group by supplier
const bySupplier = {};
let noSupplierItems = [];
let totalValue = 0;

for (const m of materials) {
  const supplierKey = m.supplier_name || null;
  const lineValue = (Number(m.quantity) || 0) * (Number(m.unit_price) || 0);
  totalValue += lineValue;

  if (!supplierKey) {
    noSupplierItems.push(m);
    continue;
  }
  if (!bySupplier[supplierKey]) {
    bySupplier[supplierKey] = { name: supplierKey, short: m.supplier_short || supplierKey, email: m.supplier_email, items: [], total: 0 };
  }
  bySupplier[supplierKey].items.push(m);
  bySupplier[supplierKey].total += lineValue;
}

let lines = [];
lines.push(`\ud83d\uded2 <b>Bestellvorschlag ${pn}</b>`);
lines.push(`${name}`);
lines.push('');

// Schedule info
if (schedule && schedule.length > 0) {
  const nextPhase = schedule.find(s => new Date(s.start_date) > new Date());
  if (nextPhase) {
    lines.push(`\ud83d\udcc5 N\u00e4chste Phase: <b>${nextPhase.trade}</b> ab ${new Date(nextPhase.start_date).toLocaleDateString('de-DE')}`);
    lines.push('');
  }
}

// Per-supplier groups
const suppliers = Object.values(bySupplier);
for (const s of suppliers) {
  const emailInfo = s.email ? `\ud83d\udce7 ${s.email}` : '\u26a0\ufe0f keine E-Mail';
  lines.push(`<b>\ud83d\udce6 ${s.short}</b> (${emailInfo})`);
  lines.push(`${s.items.length} Materialien \u00b7 ~\u20ac${s.total.toFixed(0)}`);

  // Show top 5 items
  const topItems = s.items.slice(0, 5);
  for (const item of topItems) {
    const price = item.unit_price ? ` (\u20ac${(Number(item.quantity) * Number(item.unit_price)).toFixed(0)})` : '';
    const product = item.product_name ? item.product_name : item.label;
    lines.push(`  \u2022 ${Number(item.quantity).toFixed(0)}\u00d7 ${item.unit} ${product}${price}`);
  }
  if (s.items.length > 5) {
    lines.push(`  ... +${s.items.length - 5} weitere`);
  }
  lines.push('');
}

// Items without supplier
if (noSupplierItems.length > 0) {
  lines.push(`\u26a0\ufe0f <b>${noSupplierItems.length} Materialien ohne Lieferant:</b>`);
  for (const item of noSupplierItems.slice(0, 8)) {
    lines.push(`  \u2022 ${Number(item.quantity).toFixed(0)}\u00d7 ${item.unit} ${item.label}`);
  }
  if (noSupplierItems.length > 8) {
    lines.push(`  ... +${noSupplierItems.length - 8} weitere`);
  }
  lines.push('');
}

lines.push(`<b>Gesamt: ${materials.length} Materialien \u00b7 ${suppliers.length} Lieferanten \u00b7 ~\u20ac${totalValue.toFixed(0)}</b>`);

const text = lines.join('\n');
const approveUrl = `https://n8n.srv1045913.hstgr.cloud/webhook/m4-07-order-approve?project_id=${projectId}&action=approve`;
const rejectUrl = `https://n8n.srv1045913.hstgr.cloud/webhook/m4-07-order-approve?project_id=${projectId}&action=reject`;

return [{ json: { text, projectId, approveUrl, rejectUrl, hasMaterials: true, materialCount: materials.length, totalValue: totalValue.toFixed(0) } }];

